import EventList from "../components/EventsList";

function EventsPage() {
  return (
    <>
      <div style={{ textAlign: "center" }}>
        {isLoading && <p>Loading...</p>}
        {error && <p>{error}</p>}
      </div>
      {!isLoading && fetchedEvents && <EventList events={fetchedEvents} />}
    </>
  );
}

export default EventsPage;
